/**
 * Push registration stubs for @linm/web-home.
 *
 * Push is owned by @linm/notification. These helpers dispatch CustomEvents
 * that notification's mount lifecycle listens for, allowing settings UI in
 * home to trigger registration without directly importing push internals.
 *
 *   Notification listens for:
 *     'linm:push:request-registration'  → calls initPushNotifications()
 *     'linm:push:request-deregister'    → calls deregisterPushNotifications()
 */

export function initPushNotifications(): Promise<void> {
  window.dispatchEvent(new CustomEvent('linm:push:request-registration'));
  return Promise.resolve();
}

export function deregisterPushNotifications(): Promise<void> {
  window.dispatchEvent(new CustomEvent('linm:push:request-deregister'));
  return Promise.resolve();
}
