import React from 'react';
import { useNavigate } from 'react-router-dom';
import './SessionExpiredPage.css';

/**
 * 401 – Session Expired
 *
 * Shown when the API returns 401 while the user is already inside the app
 * (token expired / revoked mid-session).  Distinct from the 403 Forbidden
 * page which is shown when the user IS authenticated but lacks permission.
 */
const SessionExpiredPage: React.FC = () => {
  const navigate = useNavigate();

  return (
    <div className="session-expired-page">
      <div className="session-expired-container">
        <div className="session-expired-icon">🔐</div>
        <h1 className="session-expired-code">401</h1>
        <h2 className="session-expired-title">Phiên đăng nhập hết hạn</h2>
        <p className="session-expired-description">
          Phiên làm việc của bạn đã hết hạn hoặc không hợp lệ.
          <br />
          Vui lòng đăng nhập lại để tiếp tục.
        </p>
        <div className="session-expired-actions">
          <button
            className="btn-primary"
            onClick={() => navigate('/login', { replace: true })}
          >
            🔑 Đăng nhập lại
          </button>
        </div>
      </div>
    </div>
  );
};

export default SessionExpiredPage;
