/**
 * useInstallPrompt
 *
 * Captures the browser's `beforeinstallprompt` event (Chrome/Edge/Android)
 * so we can show our own install button instead of relying on the browser's
 * mini-infobar.
 *
 * Returns:
 *   isInstallable  — true when the browser is ready to install and the user
 *                    hasn't installed yet (shows our button)
 *   isInstalled    — true when running as a standalone PWA (hides the button)
 *   promptInstall  — call this on button click; resolves to true if accepted
 *
 * Browser support:
 *   Chrome/Edge/Brave (desktop + Android) — full support via beforeinstallprompt
 *   Safari iOS 16.4+ PWA                  — no beforeinstallprompt; user installs
 *                                           manually via Share → Add to Home Screen
 *   Firefox                               — no beforeinstallprompt
 *
 * For unsupported browsers isInstallable stays false and the button is hidden.
 */
import { useState, useEffect, useCallback } from 'react';

// The spec interface — not yet in lib.dom.d.ts
interface BeforeInstallPromptEvent extends Event {
  prompt(): Promise<void>;
  userChoice: Promise<{ outcome: 'accepted' | 'dismissed'; platform: string }>;
}

const INSTALLED_KEY = 'pwa_installed';

// ── Module-level singleton ─────────────────────────────────────────────────
// beforeinstallprompt fires only ONCE per browser session.
// Storing it here means any hook instance mounted later (e.g. after navigation)
// can still access the prompt and show the install button correctly.
let _globalDeferredPrompt: BeforeInstallPromptEvent | null = null;

function isRunningStandalone(): boolean {
  if (typeof window === 'undefined') return false;
  return (
    window.matchMedia('(display-mode: standalone)').matches ||
    // Safari iOS standalone flag
    (window.navigator as { standalone?: boolean }).standalone === true
  );
}

/**
 * Returns true if the app is currently standalone OR was previously installed
 * (even if now browsing in a regular browser tab).
 */
function hasBeenInstalled(): boolean {
  if (isRunningStandalone()) return true;
  try {
    return localStorage.getItem(INSTALLED_KEY) === '1';
  } catch {
    return false;
  }
}

function markInstalled(): void {
  try { localStorage.setItem(INSTALLED_KEY, '1'); } catch { /* storage unavailable */ }
}

function clearInstalled(): void {
  try { localStorage.removeItem(INSTALLED_KEY); } catch { /* storage unavailable */ }
}

export interface UseInstallPromptReturn {
  /** True when the browser is ready to show the install prompt. */
  isInstallable: boolean;
  /** True when the app has been installed (persisted across tabs/sessions). */
  isInstalled: boolean;
  /** True only when currently running inside the standalone PWA window. */
  isStandalone: boolean;
  /** Triggers the browser install prompt. Returns true if user accepted. */
  promptInstall: () => Promise<boolean>;
}

export function useInstallPrompt(): UseInstallPromptReturn {
  const [deferredPrompt, setDeferredPrompt] = useState<BeforeInstallPromptEvent | null>(
    () => _globalDeferredPrompt
  );
  const [isInstallable, setIsInstallable]   = useState(
    () => _globalDeferredPrompt !== null
  );
  const [isInstalled, setIsInstalled]       = useState(hasBeenInstalled);
  const [isStandalone, setIsStandalone]     = useState(isRunningStandalone);

  useEffect(() => {
    const handleBeforeInstall = (e: Event) => {
      // beforeinstallprompt only fires when the app is NOT installed.
      // Clear any stale localStorage flag that may have survived an uninstall.
      e.preventDefault();
      clearInstalled();
      _globalDeferredPrompt = e as BeforeInstallPromptEvent;  // persist across routes
      setDeferredPrompt(e as BeforeInstallPromptEvent);
      setIsInstallable(true);
      setIsInstalled(false);
    };

    const handleAppInstalled = () => {
      markInstalled();
      _globalDeferredPrompt = null;
      setIsInstalled(true);
      setIsInstallable(false);
      setDeferredPrompt(null);
      console.log('[PWA] App installed ✅');
    };

    // Listen for display-mode change (user may install via browser menu)
    const mql = window.matchMedia('(display-mode: standalone)');
    const handleMqlChange = (e: MediaQueryListEvent) => {
      if (e.matches) {
        markInstalled();
        setIsInstalled(true);
        setIsStandalone(true);
        setIsInstallable(false);
        setDeferredPrompt(null);
      }
    };

    window.addEventListener('beforeinstallprompt', handleBeforeInstall);
    window.addEventListener('appinstalled', handleAppInstalled);
    mql.addEventListener('change', handleMqlChange);

    return () => {
      window.removeEventListener('beforeinstallprompt', handleBeforeInstall);
      window.removeEventListener('appinstalled', handleAppInstalled);
      mql.removeEventListener('change', handleMqlChange);
    };
  }, [isInstalled]);

  const promptInstall = useCallback(async (): Promise<boolean> => {
    if (!deferredPrompt) return false;
    await deferredPrompt.prompt();
    const { outcome } = await deferredPrompt.userChoice;
    console.log('[PWA] Install prompt outcome:', outcome);
    if (outcome === 'accepted') {
      markInstalled();
      _globalDeferredPrompt = null;
      setIsInstalled(true);
      setIsInstallable(false);
      setDeferredPrompt(null);
    }
    return outcome === 'accepted';
  }, [deferredPrompt]);

  return { isInstallable, isInstalled, isStandalone, promptInstall };
}
