import { UUID, Timestamps } from './common';

/**
 * Help & Documentation Models
 * Types and interfaces for help center, articles, FAQs, and support
 */

// ============================================================================
// Help Article
// ============================================================================

export interface HelpArticle extends Timestamps {
  id: UUID;
  slug: string;
  title: string;
  description: string;
  content: string; // Markdown content
  category: HelpCategory;
  tags: string[];
  author: string;
  viewCount: number;
  helpfulCount: number;
  notHelpfulCount: number;
  featured: boolean;
  readTime: number; // Reading time in minutes
  relatedArticles?: UUID[];
}

export enum HelpCategory {
  GettingStarted = 'getting-started',
  Tickets = 'tickets',
  Tasks = 'tasks',
  Approvals = 'approvals',
  Reports = 'reports',
  Settings = 'settings',
  Workflows = 'workflows',
  Troubleshooting = 'troubleshooting',
}

export interface HelpCategoryInfo {
  id: HelpCategory;
  label: string;
  icon: string;
  description: string;
  color: string;
  articleCount: number;
}

// ============================================================================
// FAQ
// ============================================================================

export interface FAQ extends Timestamps {
  id: UUID;
  question: string;
  answer: string; // Markdown
  category: HelpCategory;
  viewCount: number;
  helpfulCount: number;
  order: number;
  relatedArticles?: string[];
}

// ============================================================================
// Workflow
// ============================================================================

export interface RolesMatrixRow {
  role: string;
  roleClass: 'user' | 'staff' | 'lead' | 'manager' | 'system';
  columns: Record<string, string>;
}

export interface AssignmentStrategyRow {
  strategy: string;
  subtitle: string;
  pros: string[];
  cons: string[];
  useCases: string[];
}

export interface SLAEscalationRow {
  priority: string;
  priorityStyle: { background: string; color: string };
  responseTime: string;
  resolveTime: string;
  actions: string[];
}

export interface Workflow {
  id: string;
  type: 'ticket' | 'task' | 'incident';
  name: string;
  title: string;
  description: string;
  diagram: string; // Mermaid diagram syntax
  steps: WorkflowStep[];
  escalationRules: EscalationRule[];
  slaEscalation?: SLAEscalationRow[];
  slaEscalationNote?: string;
  departmentNote?: string[];
  rolesMatrix?: {
    columns: string[];
    rows: RolesMatrixRow[];
  };
  assignmentStrategies?: AssignmentStrategyRow[];
  progressTracking?: { items: string[]; note?: string };
  bestPractices: string[];
  lastUpdated: string;
}

export interface WorkflowStep {
  id: string;
  step: number | string;
  name: string;
  description?: string;
  role?: string;
  roles?: string[];
  roleClasses?: string[];
  actor?: string;
  duration?: string;
  actions: string[];
  statuses?: Array<{ label: string; bg: string; color: string }>;
  sla?: string;
  nextSteps?: string[];
}

export interface EscalationRule {
  id: string;
  name: string;
  trigger: string;
  condition: string;
  description: string;
  action: string;
  timeLimit?: string;
  notifyRoles?: string[];
}

// ============================================================================
// Video Tutorial
// ============================================================================

export interface VideoTutorial extends Timestamps {
  id: UUID;
  title: string;
  description: string;
  videoUrl: string;
  thumbnailUrl: string;
  duration: number; // in seconds
  category: HelpCategory;
  tags: string[];
  viewCount: number;
}

// ============================================================================
// Support Ticket
// ============================================================================

export type SupportPriority = 'low' | 'medium' | 'high' | 'urgent';
export type SupportStatus = 'open' | 'in-progress' | 'resolved' | 'closed';

export interface SupportTicket extends Timestamps {
  id: UUID;
  subject: string;
  description: string;
  category: string;
  priority: SupportPriority;
  status: SupportStatus;
  submittedBy: UUID;
  submittedByName: string;
  assignedTo?: UUID;
  assignedToName?: string;
  attachments?: string[];
}

export interface SupportTicketCreate {
  subject: string;
  description: string;
  category: string;
  priority: SupportPriority;
  attachments?: File[];
}

// ============================================================================
// Search & Feedback
// ============================================================================

export interface HelpSearchResult {
  type: 'article' | 'faq' | 'video';
  id: UUID;
  title: string;
  description: string;
  category: HelpCategory;
  url: string;
}

export interface ArticleFeedback {
  articleId: UUID;
  helpful: boolean;
}

// ============================================================================
// Utility Functions
// ============================================================================

export const getCategoryInfo = (category: HelpCategory): HelpCategoryInfo => {
  const categoryMap: Record<HelpCategory, Omit<HelpCategoryInfo, 'id' | 'articleCount'>> = {
    [HelpCategory.GettingStarted]: {
      label: 'Bắt đầu',
      icon: 'fas fa-rocket',
      description: 'Hướng dẫn cơ bản cho người dùng mới',
      color: 'var(--primary-color)',
    },
    [HelpCategory.Tickets]: {
      label: 'Phiếu yêu cầu',
      icon: 'fas fa-ticket-alt',
      description: 'Quản lý phiếu yêu cầu',
      color: '#10b981',
    },
    [HelpCategory.Tasks]: {
      label: 'Công việc',
      icon: 'fas fa-tasks',
      description: 'Quản lý công việc',
      color: '#3b82f6',
    },
    [HelpCategory.Approvals]: {
      label: 'Phê duyệt',
      icon: 'fas fa-check-double',
      description: 'Quy trình phê duyệt',
      color: '#8b5cf6',
    },
    [HelpCategory.Reports]: {
      label: 'Báo cáo',
      icon: 'fas fa-chart-bar',
      description: 'Tạo và xem báo cáo',
      color: '#f59e0b',
    },
    [HelpCategory.Settings]: {
      label: 'Cài đặt',
      icon: 'fas fa-cog',
      description: 'Cấu hình hệ thống',
      color: '#6b7280',
    },
    [HelpCategory.Workflows]: {
      label: 'Quy trình',
      icon: 'fas fa-project-diagram',
      description: 'Quy trình làm việc chi tiết',
      color: '#00897b',
    },
    [HelpCategory.Troubleshooting]: {
      label: 'Khắc phục sự cố',
      icon: 'fas fa-tools',
      description: 'Giải quyết vấn đề thường gặp',
      color: '#ef4444',
    },
  };

  return {
    id: category,
    articleCount: 0,
    ...categoryMap[category],
  };
};

export const getAllCategories = (): HelpCategoryInfo[] => {
  return Object.values(HelpCategory).map(getCategoryInfo);
};

export const formatDuration = (seconds: number): string => {
  const minutes = Math.floor(seconds / 60);
  const remainingSeconds = seconds % 60;
  return `${minutes}:${remainingSeconds.toString().padStart(2, '0')}`;
};

export const getPriorityLabel = (priority: string): string => {
  const labels: Record<string, string> = {
    low: 'Thấp',
    medium: 'Trung bình',
    high: 'Cao',
    urgent: 'Khẩn cấp',
  };
  return labels[priority] || priority;
};

export const getPriorityColor = (priority: string): string => {
  const colors: Record<string, string> = {
    low: 'var(--gray-500)',
    medium: 'var(--info-color)',
    high: 'var(--warning-color)',
    urgent: 'var(--danger-color)',
  };
  return colors[priority] || 'var(--gray-500)';
};
