import React, { ReactNode, useEffect, useRef } from 'react';
import { createPortal } from 'react-dom';
import styles from './Slideout.module.css';

export interface SlideoutProps {
  isOpen: boolean;
  onClose: () => void;
  title: string | ReactNode;
  children: ReactNode;
  width?: string | number;
  position?: 'left' | 'right';
  footer?: {
    leftLabel?: string;
    leftAction?: () => void;
    leftDisabled?: boolean;
    rightLabel?: string;
    rightAction?: () => void;
    rightDisabled?: boolean;
  };
  /** Custom footer content - renders inside the sticky footer bar instead of the generated buttons */
  customFooter?: ReactNode;
  'data-testid'?: string;
}

export const Slideout: React.FC<SlideoutProps> = ({
  isOpen,
  onClose,
  title,
  children,
  width = '600px',
  position = 'right',
  footer,
  customFooter,
  'data-testid': testId,
}) => {
  // Guard: block overlay-close clicks for 300 ms after the panel opens.
  // This lets the slide-in animation finish before the dark overlay becomes
  // closeable, preventing the UX bug where a quick re-click lands on the
  // overlay and immediately dismisses the newly-opened panel.
  const overlayClickable = useRef(false);
  useEffect(() => {
    if (!isOpen) {
      overlayClickable.current = false;
      return;
    }
    overlayClickable.current = false;
    const t = setTimeout(() => { overlayClickable.current = true; }, 300);
    return () => clearTimeout(t);
  }, [isOpen]);

  // Close on Escape key
  useEffect(() => {
    const handleEscape = (e: KeyboardEvent) => {
      if (e.key === 'Escape' && isOpen) {
        onClose();
      }
    };

    if (isOpen) {
      document.addEventListener('keydown', handleEscape);
      // Prevent body scroll when slideout is open
      document.body.style.overflow = 'hidden';
    }

    return () => {
      document.removeEventListener('keydown', handleEscape);
      document.body.style.overflow = 'unset';
    };
  }, [isOpen, onClose]);

  if (!isOpen) return null;

  const slideoutContent = (
    <div
      className={styles.overlay}
      onClick={(e) => {
        if (e.target === e.currentTarget && overlayClickable.current) {
          onClose();
        }
      }}
      data-testid={testId ? `${testId}-overlay` : undefined}
    >
      <div
        className={`${styles.slideout} ${styles[position]}`}
        style={{ width }}
        onClick={(e) => e.stopPropagation()}
        data-testid={testId}
      >
        {/* Header */}
        <div className={styles.header}>
          <div className={styles.title}>
            {typeof title === 'string' ? <h2>{title}</h2> : title}
          </div>
          <button 
            className={styles.closeButton} 
            onClick={onClose}
            aria-label="Close"
            data-testid={testId ? `${testId}-close-button` : undefined}
          >
            <svg 
              width="20" 
              height="20" 
              viewBox="0 0 20 20" 
              fill="none" 
              xmlns="http://www.w3.org/2000/svg"
            >
              <path 
                d="M15 5L5 15M5 5L15 15" 
                stroke="currentColor" 
                strokeWidth="2" 
                strokeLinecap="round" 
                strokeLinejoin="round"
              />
            </svg>
          </button>
        </div>

        {/* Content */}
        <div 
          className={styles.content}
          data-testid={testId ? `${testId}-content` : undefined}
        >
          {children}
        </div>

        {/* Footer */}
        {(footer || customFooter) && (
          <div 
            className={styles.footer}
            data-testid={testId ? `${testId}-footer` : undefined}
          >
            {customFooter ? (
              customFooter
            ) : footer ? (
              <>
                {footer.leftLabel && (
                  <button
                    onClick={footer.leftAction}
                    disabled={footer.leftDisabled}
                    className={styles.secondaryButton}
                    data-testid={testId ? `${testId}-left-button` : undefined}
                  >
                    {footer.leftLabel}
                  </button>
                )}
                {footer.rightLabel && (
                  <button
                    onClick={footer.rightAction}
                    disabled={footer.rightDisabled}
                    className={styles.primaryButton}
                    data-testid={testId ? `${testId}-right-button` : undefined}
                  >
                    {footer.rightLabel}
                  </button>
                )}
              </>
            ) : null}
          </div>
        )}
      </div>
    </div>
  );

  return createPortal(slideoutContent, document.body);
};
