import React from 'react';
import { useNavigate } from 'react-router-dom';
import styles from './QuickLinks.module.css';

interface QuickLinksProps {
  onContactClick?: () => void;
}

export const QuickLinks: React.FC<QuickLinksProps> = ({ onContactClick }) => {
  const navigate = useNavigate();

  const links = [
    {
      icon: 'fas fa-project-diagram',
      label: 'Quy trình làm việc',
      description: 'Xem các quy trình xử lý ticket và task',
      path: '/help/workflows',
    },
    {
      icon: 'fas fa-mobile-alt',
      label: 'Cài đặt ứng dụng',
      description: 'Cài QLCV lên màn hình chính trên điện thoại & máy tính',
      path: '/help/install-app',
    },
    {
      icon: 'fas fa-question-circle',
      label: 'Câu hỏi thường gặp',
      description: 'Các câu hỏi phổ biến nhất',
      path: '/help/faq',
    },
    {
      icon: 'fas fa-bell',
      label: 'Hướng dẫn Push Notification',
      description: 'Cấu hình nhận thông báo trên trình duyệt',
      path: '/help/notification-guide',
    },
    // {
    //   icon: 'fas fa-video',
    //   label: 'Video hướng dẫn',
    //   description: 'Hướng dẫn chi tiết qua video',
    //   path: '/help/videos',
    // },
    {
      icon: 'fas fa-headset',
      label: 'Liên hệ hỗ trợ',
      description: 'Gửi yêu cầu hỗ trợ',
      path: '/help/contact',
    },
  ];

  const handleClick = (link: typeof links[0]) => {
    if (link.path === '/help/contact' && onContactClick) {
      onContactClick();
    } else {
      navigate(link.path);
    }
  };

  return (
    <div className={styles.quickLinks}>
      {links.map((link) => (
        <button
          key={link.path}
          className={styles.link}
          onClick={() => handleClick(link)}
        >
          <i className={`${link.icon} ${styles.icon}`} />
          <div className={styles.content}>
            <div className={styles.label}>{link.label}</div>
            <div className={styles.description}>{link.description}</div>
          </div>
        </button>
      ))}
    </div>
  );
};
