// ── Component ─────────────────────────────────────────────────────────────────

export const NotificationGuidePage: React.FC = () => {
  useNavTitle('Hướng dẫn cấu hình Push Notification');
  const navigate = useNavigate();
  const toast = useAppToast();
  const [platform, setPlatform] = useState<PlatformTab>('chrome-mac');
  const [permission, setPermission] = useState<NotificationPermission>('default');
  const [requesting, setRequesting] = useState(false);
  const [subscribing, setSubscribing] = useState(false);

  // Read current permission on mount
  useEffect(() => {
    if ('Notification' in window) {
      setPermission(Notification.permission);
    }
  }, []);

  // Auto-detect OS + browser for default tab
  useEffect(() => {
    const ua = navigator.userAgent.toLowerCase();
    const isMac = /mac os x/.test(ua);
    const isWin = /windows/.test(ua);
    const isFirefox = /firefox/.test(ua);
    const isSafari = /safari/.test(ua) && !/chrome/.test(ua);

    if (isFirefox) setPlatform('firefox');
    else if (isSafari && isMac) setPlatform('safari-mac');
    else if (isMac) setPlatform('chrome-mac');
    else if (isWin) setPlatform('chrome-win');
  }, []);

  const handleRequestPermission = useCallback(async () => {
    if (!('Notification' in window)) {
      toast.error('Trình duyệt này không hỗ trợ Push Notification');
      return;
    }
    setRequesting(true);
    try {
      const result = await Notification.requestPermission();
      setPermission(result);
      if (result === 'granted') {
        toast.success('Đã cấp quyền thông báo! Đang đăng ký nhận push...');
        await initPushNotifications();
        toast.success('Đăng ký push notification thành công ✅');
      } else if (result === 'denied') {
        toast.error('Quyền thông báo bị từ chối. Vui lòng xem hướng dẫn bên dưới.');
      }
    } catch (err: unknown) {
      toast.fromError(err, 'Không thể yêu cầu quyền thông báo');
    } finally {
      setRequesting(false);
    }
  }, [toast]);

  const handleResubscribe = useCallback(async () => {
    if (permission !== 'granted') {
      toast.warning('Cần cấp quyền thông báo trước');
      return;
    }
    setSubscribing(true);
    try {
      await initPushNotifications();
      toast.success('Đăng ký lại push notification thành công ✅');
    } catch (err: unknown) {
      toast.fromError(err, 'Không thể đăng ký lại push notification');
    } finally {
      setSubscribing(false);
    }
  }, [permission, toast]);

  const steps = PLATFORM_STEPS[platform];

  // ── Status banner ─────────────────────────────────────────────────────────
  const renderStatusBanner = () => {
    if (!('Notification' in window)) {
      return (
        <div className={`${styles.statusBanner} ${styles.statusBannerDenied}`}>
          <i className={`fas fa-ban ${styles.statusBannerIcon}`} />
          <span className={styles.statusBannerText}>
            Trình duyệt này không hỗ trợ Web Push Notification.
          </span>
        </div>
      );
    }

    if (permission === 'granted') {
      return (
        <div className={`${styles.statusBanner} ${styles.statusBannerGranted}`}>
          <i className={`fas fa-check-circle ${styles.statusBannerIcon}`} />
          <span className={styles.statusBannerText}>
            <strong>Quyền thông báo đã được cấp.</strong> Trình duyệt này sẽ nhận push notification.
          </span>
          <button
            className={styles.statusBannerAction}
            onClick={handleResubscribe}
            disabled={subscribing}
          >
            {subscribing
              ? <><i className="fas fa-spinner fa-spin" /> Đang đăng ký...</>
              : <><i className="fas fa-redo" /> Đăng ký lại</>}
          </button>
        </div>
      );
    }

    if (permission === 'denied') {
      return (
        <div className={`${styles.statusBanner} ${styles.statusBannerDenied}`}>
          <i className={`fas fa-exclamation-triangle ${styles.statusBannerIcon}`} />
          <span className={styles.statusBannerText}>
            <strong>Quyền thông báo bị từ chối.</strong> Trình duyệt chặn popup, bạn phải mở lại trong Site Settings theo hướng dẫn bên dưới.
          </span>
        </div>
      );
    }

    // default
    return (
      <div className={`${styles.statusBanner} ${styles.statusBannerDefault}`}>
        <i className={`fas fa-bell ${styles.statusBannerIcon}`} />
        <span className={styles.statusBannerText}>
          <strong>Chưa cấp quyền thông báo.</strong> Nhấn nút bên phải để cho phép nhận push notification trên thiết bị này.
        </span>
        <button
          className={styles.statusBannerAction}
          onClick={handleRequestPermission}
          disabled={requesting}
        >
          {requesting
            ? <><i className="fas fa-spinner fa-spin" /> Đang xử lý...</>
            : <><i className="fas fa-bell" /> Cho phép thông báo</>}
        </button>
      </div>
    );
  };

  return (
    <div className={styles.page}>
      {/* Breadcrumb */}
      <div className={styles.header}>
        <nav className={styles.breadcrumb}>
          <button className={styles.breadcrumbLink} onClick={() => navigate('/help')}>
            <i className="fas fa-life-ring" /> Trợ giúp
          </button>
          <i className="fas fa-chevron-right" />
          <span>Hướng dẫn Push Notification</span>
        </nav>

        <h1 className={styles.title}>
          <i className={`fas fa-bell ${styles.titleIcon}`} />
          Hướng dẫn cấu hình Push Notification
        </h1>
        <p className={styles.subtitle}>
          Cách bật nhận thông báo đẩy (push notification) trên trình duyệt máy tính để không bỏ lỡ cảnh báo SLA và công việc mới.
        </p>
      </div>

      {/* Live permission status */}
      {renderStatusBanner()}

      {/* Step-by-step guide */}
      <div className={styles.card}>
        <div className={styles.cardHeader}>
          <i className={`fas fa-list-ol ${styles.cardHeaderIcon}`} />
          <h2 className={styles.cardTitle}>Các bước cấu hình theo trình duyệt</h2>
        </div>
        <div className={styles.cardBody}>
          {/* Platform tabs */}
          <div className={styles.platformTabs}>
            {PLATFORMS.map((p) => (
              <button
                key={p.id}
                className={`${styles.platformTab} ${platform === p.id ? styles.platformTabActive : ''}`}
                onClick={() => setPlatform(p.id)}
              >
                <i className={p.icon} /> {p.label}
              </button>
            ))}
          </div>

          {platform === 'chrome-mac' && (
            <div className={`${styles.alertBox} ${styles.alertInfo}`}>
              <i className={`fas fa-info-circle ${styles.alertIcon}`} />
              <span>
                Chrome trên macOS cần <strong>2 lớp quyền</strong>: quyền trong Chrome Site Settings <strong>VÀ</strong> quyền trong macOS System Settings. Phải bật cả hai.
              </span>
            </div>
          )}

          {platform === 'safari-mac' && (
            <div className={`${styles.alertBox} ${styles.alertWarning}`}>
              <i className={`fas fa-exclamation-triangle ${styles.alertIcon}`} />
              <span>
                Safari yêu cầu cấu hình quyền trong cả <strong>Safari Settings</strong> và <strong>macOS System Settings</strong>. Notification API trên Safari macOS 13+ (Ventura) mới hỗ trợ đầy đủ Web Push.
              </span>
            </div>
          )}

          <div className={styles.steps}>
            {steps.map((step, idx) => (
              <div key={idx} className={styles.step}>
                <div className={styles.stepNumber}>{idx + 1}</div>
                <div className={styles.stepContent}>
                  <p className={styles.stepTitle}>{step.title}</p>
                  <p className={styles.stepDesc}>{step.desc}</p>
                  {step.code && <code className={styles.stepCode}>{step.code}</code>}
                </div>
              </div>
            ))}
          </div>

          {permission === 'denied' && (
            <div className={`${styles.alertBox} ${styles.alertWarning}`}>
              <i className={`fas fa-lock ${styles.alertIcon}`} />
              <span>
                <strong>Quyền đã bị chặn.</strong> Chrome/Firefox không cho phép hiện popup nữa. Bạn phải vào Site Settings thủ công (Bước 1 hoặc 2 tùy trình duyệt), đặt lại về "Default" hoặc "Allow" rồi reload trang.
              </span>
            </div>
          )}
        </div>
      </div>

      {/* Verify section */}
      <div className={styles.card}>
        <div className={styles.cardHeader}>
          <i className={`fas fa-check-double ${styles.cardHeaderIcon}`} />
          <h2 className={styles.cardTitle}>Xác nhận đã hoạt động</h2>
        </div>
        <div className={styles.cardBody}>
          <div className={styles.verifySteps}>
            {[
              'Mở DevTools (F12) → Console → Tìm dòng "[Push:VAPID] Subscription registered ✅"',
              'Vào DevTools → Application → Service Workers → Kiểm tra sw.js đang "activated and running"',
              'Vào DevTools → Application → Push Messaging → Thấy subscription đang active',
              'Trong Settings → Thông báo → Kiểm tra trạng thái Push: "Đang hoạt động"',
              'Yêu cầu IT gửi test notification để xác nhận nhận được',
            ].map((item, idx) => (
              <div key={idx} className={styles.verifyItem}>
                <i className={`fas fa-chevron-right ${styles.verifyIcon}`} />
                <span>{item}</span>
              </div>
            ))}
          </div>

          <div className={`${styles.alertBox} ${styles.alertSuccess}`}>
            <i className={`fas fa-lightbulb ${styles.alertIcon}`} />
            <span>
              Sau khi đăng nhập lại, hệ thống sẽ <strong>tự động đăng ký</strong> nhận push notification. Không cần thao tác thêm nếu đã cấp quyền đúng.
            </span>
          </div>
        </div>
      </div>

      {/* Troubleshooting */}
      <div className={styles.card}>
        <div className={styles.cardHeader}>
          <i className={`fas fa-tools ${styles.cardHeaderIcon}`} />
          <h2 className={styles.cardTitle}>Xử lý sự cố thường gặp</h2>
        </div>
        <div className={styles.cardBody}>
          <table className={styles.troubleshootTable}>
            <thead>
              <tr>
                <th style={{ width: '35%' }}>Vấn đề</th>
                <th style={{ width: '25%' }}>Nguyên nhân</th>
                <th>Cách khắc phục</th>
              </tr>
            </thead>
            <tbody>
              {TROUBLESHOOT_ROWS.map((row, idx) => (
                <tr key={idx}>
                  <td>{row.issue}</td>
                  <td>{row.cause}</td>
                  <td>{row.fix}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Back button */}
      <button className={styles.backBtn} onClick={() => navigate('/help')}>
        <i className="fas fa-arrow-left" /> Quay lại Trợ giúp
      </button>
    </div>
  );
};
