import React from 'react';
import styles from './IconButton.module.css';

export interface IconButtonProps {
  icon: string; // Font Awesome class name, e.g. "fas fa-edit"
  variant?: 'primary' | 'secondary' | 'danger' | 'ghost';
  size?: 'sm' | 'md' | 'lg';
  disabled?: boolean;
  onClick?: () => void;
  ariaLabel: string;
  className?: string;
  badge?: number | string;
}

export const IconButton: React.FC<IconButtonProps> = ({
  icon,
  variant = 'ghost',
  size = 'md',
  disabled = false,
  onClick,
  ariaLabel,
  className = '',
  badge,
}) => {
  const classNames = [
    styles.iconButton,
    styles[variant],
    styles[size],
    className,
  ]
    .filter(Boolean)
    .join(' ');

  return (
    <button
      type="button"
      className={classNames}
      disabled={disabled}
      onClick={onClick}
      aria-label={ariaLabel}
    >
      <i className={`${icon}`}></i>
      {badge && <span className={styles.badge}>{badge}</span>}
    </button>
  );
};
