import React, { useState, useEffect } from 'react';
import { useNavTitle } from '@linm-soft/common-components';
import { FAQ, HelpCategory } from '../../models/Help';
import { helpService } from '../../services/helpService';
import { useAppToast } from '../../hooks/useAppToast';
import { FAQList } from '../../components/help/FAQList';
import { FAQCategoryFilter } from '../../components/help/FAQCategoryFilter';
import styles from './FAQPage.module.css';

export const FAQPage: React.FC = () => {
  useNavTitle('Câu hỏi thường gặp');
  const toast = useAppToast();
  const [faqs, setFaqs] = useState<FAQ[]>([]);
  const [selectedCategory, setSelectedCategory] = useState<HelpCategory | undefined>();
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [retryKey, setRetryKey] = useState(0);

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    setError(null);
    const timer = setTimeout(() => {
      if (cancelled) return;
      helpService.getFAQs(selectedCategory)
        .then((data) => { if (!cancelled) setFaqs(data); })
        .catch((err: unknown) => { if (!cancelled) { toast.fromError(err, 'Không thể tải câu hỏi. Vui lòng thử lại.'); setError('Không thể tải câu hỏi. Vui lòng thử lại.'); } })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(timer); };
  }, [selectedCategory, retryKey]);

  return (
    <div className={styles.faqPage}>
      {/* Header */}
      <div className={styles.header}>
        <h1 className={styles.title}>Câu hỏi thường gặp</h1>
        <p className={styles.subtitle}>
          Tìm câu trả lời nhanh chóng cho các thắc mắc phổ biến
        </p>
      </div>

      {/* Category Filter */}
      <FAQCategoryFilter
        selectedCategory={selectedCategory}
        onCategoryChange={setSelectedCategory}
      />

      {/* FAQ List */}
      {loading ? (
        <div className={styles.loading}>
          <i className="fas fa-spinner fa-spin"></i> Đang tải...
        </div>
      ) : error ? (
        <div className={styles.error}>
          <i className="fas fa-exclamation-circle"></i>
          <p>{error}</p>
          <button className={styles.retryButton} onClick={() => setRetryKey((k) => k + 1)}>
            <i className="fas fa-redo"></i> Thử lại
          </button>
        </div>
      ) : faqs.length === 0 ? (
        <div className={styles.empty}>Không tìm thấy câu hỏi nào</div>
      ) : (
        <FAQList faqs={faqs} />
      )}
    </div>
  );
};
